// MARK: - Network Security Policy
enum NetworkSecurityPolicy {
    case secure
    case insecure
    case mixed
    
    func evaluate(trust: SecTrust, host: String) -> Bool {
        switch self {
        case .secure:
            return evaluateSecureTrust(trust, host: host)
        case .insecure:
            return true
        case .mixed:
            return evaluateMixedTrust(trust, host: host)
        }
    }
    
    private func evaluateSecureTrust(_ trust: SecTrust, host: String) -> Bool {
        var secResult = errSecSuccess
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(trust, policy)
        
        secResult = SecTrustEvaluate(trust, nil)
        let result = SecTrustCopyTrustResult(trust, nil)
        
        return secResult == errSecSuccess && (result?.pointee == .unspecified || result?.pointee == .proceed)
    }
    
    private func evaluateMixedTrust(_ trust: SecTrust, host: String) -> Bool {
        // Allow both secure and insecure connections
        return true
    }
}

// MARK: - HTTP Request Builder
struct HTTPRequestBuilder {
    static func buildRequest(url: URL, method: HTTPMethod = .get, headers: [String: String] = [:], body: Data? = nil) -> URLRequest {
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.timeoutInterval = HTTPClientConfig.shared.timeout
        
        for (key, value) in headers {
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        if let body = body {
            request.httpBody = body
        }
        
        return request
    }
}

