// MARK: - URLSession Delegate
extension HTTPClient: URLSessionDelegate, URLSessionTaskDelegate {
    func urlSession(_ session: URLSession, task: URLSessionTask, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // Allow local network devices to use insecure connections
        if HTTPClientConfig.shared.allowLocalNetworkAccess,
           host.starts(with: "192.168."),
           HTTPClientConfig.shared.allowInsecureConnections {
            let credential = URLCredential(trust: challenge.protectionSpace.serverTrust!)
            completionHandler(.useCredential, credential)
            return
        }
        
        // For cloud API, use secure policy
        if host.contains("api.example.com") {
            let policy = NetworkSecurityPolicy.secure
            if policy.evaluate(trust: challenge.protectionSpace.serverTrust!, host: host) {
                let credential = URLCredential(trust: challenge.protectionSpace.serverTrust!)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        } else {
            // For other domains, allow mixed security
            let policy = NetworkSecurityPolicy.mixed
            if policy.evaluate(trust: challenge.protectionSpace.serverTrust!, host: host) {
                let credential = URLCredential(trust: challenge.protectionSpace.serverTrust!)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        }
    }
    
    func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
        // Handle task completion
    }
}

